    const p2Images = [
      { variantId: savedP2Variants[0].id, imageUrl: 'https://picsum.photos/seed/rkmd-blk-1/800/1200', altText: 'Ribbed Knit Midi Dress Black front', isPrimary: true, sortOrder: 0 },
      { variantId: savedP2Variants[0].id, imageUrl: 'https://picsum.photos/seed/rkmd-blk-2/800/1200', altText: 'Ribbed Knit Midi Dress Black side', isPrimary: false, sortOrder: 1 },
      { variantId: savedP2Variants[3].id, imageUrl: 'https://picsum.photos/seed/rkmd-brg-1/800/1200', altText: 'Ribbed Knit Midi Dress Burgundy front', isPrimary: true, sortOrder: 0 },
      { variantId: savedP2Variants[5].id, imageUrl: 'https://picsum.photos/seed/rkmd-oat-1/800/1200', altText: 'Ribbed Knit Midi Dress Oatmeal front', isPrimary: true, sortOrder: 0 },
      { variantId: savedP2Variants[5].id, imageUrl: 'https://picsum.photos/seed/rkmd-oat-2/800/1200', altText: 'Ribbed Knit Midi Dress Oatmeal detail', isPrimary: false, sortOrder: 1 },
    ];
    await imageRepo.save(p2Images.map((img) => imageRepo.create(img)));

    // Attribute values for product 2
    const p2AttrValues = [
      { productId: product2.id, attributeId: materialAttr.id, value: '60% Cotton, 40% Modal', normalizedValue: '60% cotton, 40% modal' },
      { productId: product2.id, attributeId: fitAttr.id, value: 'Slim', normalizedValue: 'slim' },
    ];
    await attrValueRepo.save(p2AttrValues.map((av) => attrValueRepo.create(av)));

    console.log('Product 2 (Ribbed Knit Midi Dress) seeded with 6 variants.');

    await queryRunner.commitTransaction();
    console.log('Seed completed successfully!');
  } catch (error) {
    await queryRunner.rollbackTransaction();
    console.error('Seed failed, transaction rolled back:', error);
    process.exit(1);
  } finally {
    await queryRunner.release();
    await dataSource.destroy();
  }
}

