import {
  Check,
  Column,
  CreateDateColumn,
  Entity,
  Index,
  JoinColumn,
  ManyToOne,
  OneToMany,
  PrimaryColumn,
  UpdateDateColumn,
} from 'typeorm';
import { ProductStatus } from '../../../common/enums/product-status.enum';
import { ProductAttributeValueEntity } from './product-attribute-value.entity';
import { ProductCategoryEntity } from './product-category.entity';
import { ProductVariantEntity } from './product-variant.entity';

@Entity({ name: 'products' })
@Index(['status', 'isActive'])
@Index(['categoryId', 'status', 'isActive'])
@Check('"min_price" <= "max_price"')
@Check('"total_stock" >= 0')
@Check('"rating_count" >= 0')
export class ProductEntity {
  @PrimaryColumn({ type: 'uuid', default: () => 'gen_random_uuid()' })
  id!: string;

  @Column({ type: 'varchar', length: 255 })
  name!: string;

  @Index({ unique: true })
  @Column({ type: 'varchar', length: 255 })
  slug!: string;

  @Column({ name: 'short_description', type: 'varchar', length: 500, nullable: true })
  shortDescription: string | null = null;

  @Column({ type: 'text', nullable: true })
  description: string | null = null;

  @Index()
  @Column({ type: 'varchar', length: 120, nullable: true })
  brand: string | null = null;

  @Column({ name: 'category_id', type: 'uuid' })
  categoryId!: string;

  @ManyToOne(() => ProductCategoryEntity, (category) => category.products, {
    onDelete: 'RESTRICT',
  })
  @JoinColumn({ name: 'category_id' })
  category!: ProductCategoryEntity;

  @Column({ name: 'sub_category', type: 'varchar', length: 120, nullable: true })
  subCategory: string | null = null;

  @Column({
    type: 'enum',
    enum: ProductStatus,
    default: ProductStatus.DRAFT,
  })
  status!: ProductStatus;

  @Column({ name: 'base_currency', type: 'char', length: 3, default: 'USD' })
  baseCurrency!: string;

  @Column({ name: 'min_price', type: 'numeric', precision: 12, scale: 2, default: '0.00' })
  minPrice!: string;

  @Column({ name: 'max_price', type: 'numeric', precision: 12, scale: 2, default: '0.00' })
  maxPrice!: string;

  @Column({ name: 'total_stock', type: 'integer', default: 0 })
  totalStock!: number;

  @Column({ name: 'is_featured', type: 'boolean', default: false })
  isFeatured!: boolean;

  @Column({ name: 'is_active', type: 'boolean', default: true })
  isActive!: boolean;

  @Column({
    name: 'rating_average',
    type: 'numeric',
    precision: 3,
    scale: 2,
    nullable: true,
  })
  ratingAverage: string | null = null;

  @Column({ name: 'rating_count', type: 'integer', default: 0 })
  ratingCount!: number;

  @Column({ type: 'text', array: true, default: () => "'{}'" })
  tags!: string[];

  @Column({ type: 'jsonb', nullable: true })
  metadata: Record<string, unknown> | null = null;

  @OneToMany(() => ProductVariantEntity, (variant) => variant.product)
  variants!: ProductVariantEntity[];

  @OneToMany(() => ProductAttributeValueEntity, (attributeValue) => attributeValue.product)
  attributeValues!: ProductAttributeValueEntity[];

  @CreateDateColumn({ name: 'created_at' })
  createdAt!: Date;

  @UpdateDateColumn({ name: 'updated_at' })
  updatedAt!: Date;
}

