import {
  Check,
  Column,
  CreateDateColumn,
  Entity,
  Index,
  JoinColumn,
  ManyToOne,
  OneToMany,
  PrimaryColumn,
  UpdateDateColumn,
} from 'typeorm';
import { ProductEntity } from './product.entity';
import { ProductVariantImageEntity } from './product-variant-image.entity';
import { CartItemEntity } from '../../carts/entities/cart-item.entity';
import { WishlistItemEntity } from '../../wishlists/entities/wishlist-item.entity';

@Entity({ name: 'product_variants' })
@Index(['productId', 'isActive'])
@Check('"stock_quantity" >= 0')
@Check('"reserved_quantity" >= 0')
@Check('"reserved_quantity" <= "stock_quantity"')
@Check('"compare_at_price" IS NULL OR "compare_at_price" >= "price"')
export class ProductVariantEntity {
  @PrimaryColumn({ type: 'uuid', default: () => 'gen_random_uuid()' })
  id!: string;

  @Column({ name: 'product_id', type: 'uuid' })
  productId!: string;

  @ManyToOne(() => ProductEntity, (product) => product.variants, {
    onDelete: 'CASCADE',
  })
  @JoinColumn({ name: 'product_id' })
  product!: ProductEntity;

  @Index({ unique: true })
  @Column({ type: 'varchar', length: 100 })
  sku!: string;

  @Column({ type: 'varchar', length: 160, nullable: true })
  title: string | null = null;

  @Index()
  @Column({ name: 'color_name', type: 'varchar', length: 60, nullable: true })
  colorName: string | null = null;

  @Column({ name: 'color_hex', type: 'char', length: 7, nullable: true })
  colorHex: string | null = null;

  @Column({ type: 'varchar', length: 40, nullable: true })
  size: string | null = null;

  @Column({ type: 'numeric', precision: 12, scale: 2 })
  price!: string;

  @Column({ name: 'compare_at_price', type: 'numeric', precision: 12, scale: 2, nullable: true })
  compareAtPrice: string | null = null;

  @Column({ name: 'stock_quantity', type: 'integer', default: 0 })
  stockQuantity!: number;

  @Column({ name: 'reserved_quantity', type: 'integer', default: 0 })
  reservedQuantity!: number;

  @Column({ name: 'is_active', type: 'boolean', default: true })
  isActive!: boolean;

  @Column({ name: 'weight_grams', type: 'integer', nullable: true })
  weightGrams: number | null = null;

  @Index({ unique: true })
  @Column({ type: 'varchar', length: 100, nullable: true })
  barcode: string | null = null;

  @OneToMany(() => ProductVariantImageEntity, (image) => image.variant)
  images!: ProductVariantImageEntity[];

  @OneToMany(() => CartItemEntity, (cartItem) => cartItem.productVariant)
  cartItems!: CartItemEntity[];

  @OneToMany(() => WishlistItemEntity, (wishlistItem) => wishlistItem.productVariant)
  wishlistItems!: WishlistItemEntity[];

  @Column({ type: 'jsonb', nullable: true })
  metadata: Record<string, unknown> | null = null;

  @CreateDateColumn({ name: 'created_at' })
  createdAt!: Date;

  @UpdateDateColumn({ name: 'updated_at' })
  updatedAt!: Date;
}

import 'reflect-metadata';
import { config } from 'dotenv';
import { ConfigService } from '@nestjs/config';
import configuration from '../config/configuration';
import { getTypeOrmDataSourceOptions } from './typeorm.config';
import { DataSource } from 'typeorm';
import { ProductCategoryEntity } from '../modules/products/entities/product-category.entity';
import { ProductEntity } from '../modules/products/entities/product.entity';
import { ProductVariantEntity } from '../modules/products/entities/product-variant.entity';
import { ProductVariantImageEntity } from '../modules/products/entities/product-variant-image.entity';
import { ProductAttributeEntity } from '../modules/products/entities/product-attribute.entity';
import { ProductAttributeValueEntity } from '../modules/products/entities/product-attribute-value.entity';
import { ProductStatus } from '../common/enums/product-status.enum';

config();

const values = configuration();
const configService = new ConfigService(values);
const dataSource = new DataSource(getTypeOrmDataSourceOptions(configService));

async function seed() {
  await dataSource.initialize();
  console.log('Database connected.');

  const queryRunner = dataSource.createQueryRunner();
  await queryRunner.startTransaction();

  try {
    const categoryRepo = queryRunner.manager.getRepository(ProductCategoryEntity);
    const productRepo = queryRunner.manager.getRepository(ProductEntity);
    const variantRepo = queryRunner.manager.getRepository(ProductVariantEntity);
    const imageRepo = queryRunner.manager.getRepository(ProductVariantImageEntity);
    const attributeRepo = queryRunner.manager.getRepository(ProductAttributeEntity);
    const attrValueRepo = queryRunner.manager.getRepository(ProductAttributeValueEntity);

    // --- Categories ---
    const menCategory = categoryRepo.create({
      name: 'Men',
      slug: 'men',
      isActive: true,
      sortOrder: 0,
    });
    const womenCategory = categoryRepo.create({
      name: 'Women',
      slug: 'women',
      isActive: true,
      sortOrder: 1,
    });
    await categoryRepo.save([menCategory, womenCategory]);
    console.log('Categories seeded.');

    // --- Attributes ---
    const materialAttr = attributeRepo.create({
      code: 'material',
      name: 'Material',
      description: 'Fabric or material composition',
      isFilterable: true,
      sortOrder: 0,
    });
    const fitAttr = attributeRepo.create({
      code: 'fit',
      name: 'Fit',
      description: 'Garment fit type',
      isFilterable: true,
      sortOrder: 1,
    });
    await attributeRepo.save([materialAttr, fitAttr]);
    console.log('Attributes seeded.');

    // ========================================
    // PRODUCT 1: Classic Cotton T-Shirt (Men)
    // ========================================
    const product1 = productRepo.create({
      name: 'Classic Cotton T-Shirt',
      slug: 'classic-cotton-t-shirt',
      shortDescription: 'A timeless cotton crew-neck tee for everyday wear.',
      description:
        'Crafted from 100% organic cotton, this classic crew-neck t-shirt offers a comfortable, breathable fit. Perfect for layering or wearing on its own. Pre-shrunk fabric ensures a consistent fit wash after wash.',
      brand: 'Tinz Essentials',
      categoryId: menCategory.id,
      subCategory: 'T-Shirts',
      status: ProductStatus.ACTIVE,
      baseCurrency: 'USD',
      minPrice: 24.99,
      maxPrice: 29.99,
      totalStock: 150,
      isFeatured: true,
      isActive: true,
      ratingAverage: 4.5,
      ratingCount: 42,
      tags: ['cotton', 'basics', 'crew-neck', 'organic'],
      metadata: { careInstructions: 'Machine wash cold, tumble dry low' },
    });
    await productRepo.save(product1);

    // Variants for product 1
    const p1Variants = [
      {
        productId: product1.id,
        sku: 'CCT-BLK-S',
        title: 'Classic Cotton T-Shirt - Black / S',
        colorName: 'Black',
        colorHex: '#000000',
        size: 'S',
        price: 24.99,
        compareAtPrice: 29.99,
        stockQuantity: 25,
        reservedQuantity: 2,
        isActive: true,
        weightGrams: 180,
      },
      {
        productId: product1.id,
        sku: 'CCT-BLK-M',
        title: 'Classic Cotton T-Shirt - Black / M',
        colorName: 'Black',
        colorHex: '#000000',
        size: 'M',
        price: 24.99,
        compareAtPrice: 29.99,
        stockQuantity: 30,
        reservedQuantity: 5,
        isActive: true,
        weightGrams: 200,
      },
      {
        productId: product1.id,
        sku: 'CCT-BLK-L',
        title: 'Classic Cotton T-Shirt - Black / L',
        colorName: 'Black',
        colorHex: '#000000',
        size: 'L',
        price: 24.99,
        compareAtPrice: 29.99,
        stockQuantity: 20,
        reservedQuantity: 0,
        isActive: true,
        weightGrams: 220,
      },
      {
        productId: product1.id,
        sku: 'CCT-WHT-S',
        title: 'Classic Cotton T-Shirt - White / S',
        colorName: 'White',
        colorHex: '#FFFFFF',
        size: 'S',
        price: 24.99,
        compareAtPrice: 29.99,
        stockQuantity: 25,
        reservedQuantity: 0,
        isActive: true,
        weightGrams: 180,
      },
      {
        productId: product1.id,
        sku: 'CCT-WHT-M',
        title: 'Classic Cotton T-Shirt - White / M',
        colorName: 'White',
        colorHex: '#FFFFFF',
        size: 'M',
        price: 24.99,
        compareAtPrice: 29.99,
        stockQuantity: 30,
        reservedQuantity: 3,
        isActive: true,
        weightGrams: 200,
      },
      {
        productId: product1.id,
        sku: 'CCT-NVY-M',
        title: 'Classic Cotton T-Shirt - Navy / M',
        colorName: 'Navy',
        colorHex: '#1B2A4A',
        size: 'M',
        price: 29.99,
        compareAtPrice: 29.99,
        stockQuantity: 20,
        reservedQuantity: 1,
        isActive: true,
        weightGrams: 200,
      },
    ];
    const savedP1Variants = await variantRepo.save(p1Variants.map((v) => variantRepo.create(v)));

    // Images for product 1 variants
    const p1Images = [
      { variantId: savedP1Variants[0].id, imageUrl: 'https://picsum.photos/seed/cct-blk-1/800/1000', altText: 'Classic Cotton T-Shirt Black front', isPrimary: true, sortOrder: 0 },
      { variantId: savedP1Variants[0].id, imageUrl: 'https://picsum.photos/seed/cct-blk-2/800/1000', altText: 'Classic Cotton T-Shirt Black back', isPrimary: false, sortOrder: 1 },
      { variantId: savedP1Variants[3].id, imageUrl: 'https://picsum.photos/seed/cct-wht-1/800/1000', altText: 'Classic Cotton T-Shirt White front', isPrimary: true, sortOrder: 0 },
      { variantId: savedP1Variants[5].id, imageUrl: 'https://picsum.photos/seed/cct-nvy-1/800/1000', altText: 'Classic Cotton T-Shirt Navy front', isPrimary: true, sortOrder: 0 },
    ];
    await imageRepo.save(p1Images.map((img) => imageRepo.create(img)));

    // Attribute values for product 1
    const p1AttrValues = [
      { productId: product1.id, attributeId: materialAttr.id, value: '100% Organic Cotton', normalizedValue: '100% organic cotton' },
      { productId: product1.id, attributeId: fitAttr.id, value: 'Regular', normalizedValue: 'regular' },
    ];
    await attrValueRepo.save(p1AttrValues.map((av) => attrValueRepo.create(av)));

    console.log('Product 1 (Classic Cotton T-Shirt) seeded with 6 variants.');

    // =============================================
    // PRODUCT 2: Ribbed Knit Midi Dress (Women)
    // =============================================
    const product2 = productRepo.create({
      name: 'Ribbed Knit Midi Dress',
      slug: 'ribbed-knit-midi-dress',
      shortDescription: 'An elegant ribbed knit midi dress with a flattering silhouette.',
      description:
        'This ribbed knit midi dress combines comfort with style. Made from a soft cotton-modal blend, it features a figure-hugging fit, scoop neckline, and side slit detail. Versatile enough for both casual outings and dressed-up evenings.',
