324	  private validateVariantPayload(variants: CreateProductVariantDto[]): void {
325	    const uniqueSkus = new Set<string>();
326	    const normalizedColorSizeKeys = new Set<string>();
327	
328	    for (const variant of variants) {
329	      const sku = this.normalizeText(variant.sku).toLowerCase();
330	      if (uniqueSkus.has(sku)) {
331	        throw new BadRequestException(`Duplicate SKU found in payload: ${variant.sku}`);
332	      }
333	      uniqueSkus.add(sku);
334	
335	      const color = (variant.colorName ?? '').trim().toLowerCase();
336	      const size = (variant.size ?? '').trim().toLowerCase();
337	      const colorSizeKey = `${color}::${size}`;
338	      if (color || size) {
339	        if (normalizedColorSizeKeys.has(colorSizeKey)) {
340	          throw new BadRequestException(
341	            `Duplicate variant combination for color "${variant.colorName ?? '-'}" and size "${variant.size ?? '-'}"`,
342	          );
343	        }
