349	  private computeInventorySummary(variants: ProductVariantUpsertData[]): {
350	    minPrice: string;
351	    maxPrice: string;
352	    totalStock: number;
353	  } {
354	    const activeVariants = variants.filter((variant) => variant.isActive);
355	    const sourceVariants = activeVariants.length > 0 ? activeVariants : variants;
356	    const prices = sourceVariants.map((variant) => Number(variant.price));
357	    const minPrice = Math.min(...prices);
358	    const maxPrice = Math.max(...prices);
359	    const totalStock = sourceVariants.reduce((sum, variant) => sum + variant.stockQuantity, 0);
360	
361	    return {
362	      minPrice: this.numberToMoneyString(minPrice),
363	      maxPrice: this.numberToMoneyString(maxPrice),
364	      totalStock,
365	    };
366	  }
