417	  private async runWithErrorHandling<T>(operation: string, callback: () => Promise<T>): Promise<T> {
418	    try {
419	      return await callback();
420	    } catch (error) {
421	      if (error instanceof HttpException) {
422	        throw error;
423	      }
424	
425	      if (error instanceof QueryFailedError) {
