431	          throw new BadRequestException('A variant with this SKU already exists');
432	        }
433	        if (errorMessage.includes('product_variants_barcode_key')) {
434	          throw new BadRequestException('A variant with this barcode already exists');
435	        }
436	      }
437	
438	      this.logger.error(`Unexpected error while trying to ${operation}`, error);
439	      throw new InternalServerErrorException(`Unable to ${operation} right now`);
440	    }
441	  }
