import type { ProductStatus } from '../../../common/enums/product-status.enum';
import type { ProductCategoryEntity } from '../entities/product-category.entity';
import type { ProductEntity } from '../entities/product.entity';

export type ProductSortBy = 'newest' | 'priceAsc' | 'priceDesc' | 'nameAsc';

export interface ProductVariantImageUpsertData {
  imageUrl: string;
  altText: string | null;
  isPrimary: boolean;
  sortOrder: number;
}

export interface ProductVariantUpsertData {
  sku: string;
  title: string | null;
  colorName: string | null;
  colorHex: string | null;
  size: string | null;
  price: string;
  compareAtPrice: string | null;
  stockQuantity: number;
  reservedQuantity: number;
  isActive: boolean;
  weightGrams: number | null;
  barcode: string | null;
  metadata: Record<string, unknown> | null;
  images: ProductVariantImageUpsertData[];
}

export interface ProductAttributeValueUpsertData {
  attributeCode: string;
  attributeName: string | null;
  value: string;
  normalizedValue: string;
}

export interface ProductCreateData {
  name: string;
  slug: string;
  shortDescription: string | null;
  description: string | null;
  brand: string | null;
  categoryId: string;
  subCategory: string | null;
  status: ProductStatus;
  baseCurrency: string;
  isFeatured: boolean;
  isActive: boolean;
  tags: string[];
  metadata: Record<string, unknown> | null;
  minPrice: string;
  maxPrice: string;
  totalStock: number;
  variants: ProductVariantUpsertData[];
  attributeValues: ProductAttributeValueUpsertData[];
}

export interface ProductUpdateData {
  name?: string;
  slug?: string;
  shortDescription?: string | null;
  description?: string | null;
  brand?: string | null;
  categoryId?: string;
  subCategory?: string | null;
  status?: ProductStatus;
  baseCurrency?: string;
  isFeatured?: boolean;
  isActive?: boolean;
  tags?: string[];
  metadata?: Record<string, unknown> | null;
  minPrice?: string;
  maxPrice?: string;
  totalStock?: number;
  variants?: ProductVariantUpsertData[];
  attributeValues?: ProductAttributeValueUpsertData[];
  replaceVariants?: boolean;
  replaceAttributeValues?: boolean;
}

export interface ProductListFilters {
  q?: string;
  categoryId?: string;
  category?: string;
  brand?: string;
  status?: ProductStatus;
  isActive?: boolean;
  isFeatured?: boolean;
  minPrice?: number;
  maxPrice?: number;
  color?: string;
  size?: string;
  tags?: string[];
  attributeCode?: string;
  attributeValue?: string;
  page: number;
  limit: number;
  sortBy: ProductSortBy;
}

export interface ProductListResult {
  items: ProductEntity[];
  total: number;
  page: number;
  limit: number;
}

export interface ProductFilterPriceRange {
  min: string;
  max: string;
}

export interface ProductFilterCategoryOption {
  id: string;
  name: string;
  slug: string;
  count: number;
}

export interface ProductFilterAttributeOption {
  code: string;
  name: string;
  values: string[];
}

export interface ProductFiltersResult {
  priceRange: ProductFilterPriceRange;
  categories: ProductFilterCategoryOption[];
  brands: string[];
  colors: string[];
  sizes: string[];
  tags: string[];
  attributes: ProductFilterAttributeOption[];
}

export interface IProductsRepository {
  createProduct(data: ProductCreateData): Promise<ProductEntity>;
  findCategoryById(categoryId: string): Promise<ProductCategoryEntity | null>;
  findById(productId: string): Promise<ProductEntity | null>;
  findBySlug(slug: string): Promise<ProductEntity | null>;
  findByIdOrSlug(identifier: string): Promise<ProductEntity | null>;
  findMany(filters: ProductListFilters): Promise<ProductListResult>;
  findManyPublic(filters: ProductListFilters): Promise<ProductListResult>;
  findPublicFilters(): Promise<ProductFiltersResult>;
  updateProduct(productId: string, data: ProductUpdateData): Promise<ProductEntity | null>;
  deleteById(productId: string): Promise<boolean>;
}

export const PRODUCTS_REPOSITORY = Symbol('PRODUCTS_REPOSITORY');

