1	import { Injectable, Logger } from '@nestjs/common';
2	import { InjectRepository } from '@nestjs/typeorm';
3	import { DataSource, EntityManager, Repository, SelectQueryBuilder } from 'typeorm';
4	import { ProductStatus } from '../../../common/enums/product-status.enum';
5	import { ProductAttributeEntity } from '../entities/product-attribute.entity';
6	import { ProductAttributeValueEntity } from '../entities/product-attribute-value.entity';
7	import { ProductCategoryEntity } from '../entities/product-category.entity';
8	import { ProductEntity } from '../entities/product.entity';
9	import { ProductVariantImageEntity } from '../entities/product-variant-image.entity';
10	import { ProductVariantEntity } from '../entities/product-variant.entity';
11	import {
12	  IProductsRepository,
13	  ProductCreateData,
14	  ProductFiltersResult,
15	  ProductListFilters,
16	  ProductListResult,
17	  ProductSortBy,
18	  ProductUpdateData,
19	} from './products.repository.interface';
20	
21	@Injectable()
22	export class ProductsRepository implements IProductsRepository {
23	  private readonly logger = new Logger(ProductsRepository.name);
24	
25	  constructor(
26	    private readonly dataSource: DataSource,
27	    @InjectRepository(ProductEntity)
28	    private readonly productOrmRepository: Repository<ProductEntity>,
29	    @InjectRepository(ProductCategoryEntity)
30	    private readonly productCategoryOrmRepository: Repository<ProductCategoryEntity>,
31	  ) {}
32	
33	  async createProduct(data: ProductCreateData): Promise<ProductEntity> {
34	    return this.runInTransaction('createProduct', async (manager) => {
35	      const productRepository = manager.getRepository(ProductEntity);
36	      const variantRepository = manager.getRepository(ProductVariantEntity);
37	      const imageRepository = manager.getRepository(ProductVariantImageEntity);
38	      const attributeRepository = manager.getRepository(ProductAttributeEntity);
39	      const attributeValueRepository = manager.getRepository(ProductAttributeValueEntity);
40	
41	      const product = productRepository.create({
42	        name: data.name,
43	        slug: data.slug,
44	        shortDescription: data.shortDescription,
45	        description: data.description,
46	        brand: data.brand,
47	        categoryId: data.categoryId,
48	        subCategory: data.subCategory,
49	        status: data.status,
50	        baseCurrency: data.baseCurrency,
51	        minPrice: data.minPrice,
52	        maxPrice: data.maxPrice,
53	        totalStock: data.totalStock,
54	        isFeatured: data.isFeatured,
55	        isActive: data.isActive,
56	        tags: data.tags,
57	        metadata: data.metadata,
58	      });
59	      const savedProduct = await productRepository.save(product);
60	
61	      for (const variantInput of data.variants) {
62	        const variant = await variantRepository.save(
63	          variantRepository.create({
64	            productId: savedProduct.id,
65	            sku: variantInput.sku,
66	            title: variantInput.title,
67	            colorName: variantInput.colorName,
68	            colorHex: variantInput.colorHex,
69	            size: variantInput.size,
70	            price: variantInput.price,
71	            compareAtPrice: variantInput.compareAtPrice,
72	            stockQuantity: variantInput.stockQuantity,
73	            reservedQuantity: variantInput.reservedQuantity,
74	            isActive: variantInput.isActive,
75	            weightGrams: variantInput.weightGrams,
76	            barcode: variantInput.barcode,
77	            metadata: variantInput.metadata,
78	          }),
79	        );
80	
81	        for (const imageInput of variantInput.images) {
82	          const image = imageRepository.create({
83	            variantId: variant.id,
84	            imageUrl: imageInput.imageUrl,
85	            altText: imageInput.altText,
86	            isPrimary: imageInput.isPrimary,
87	            sortOrder: imageInput.sortOrder,
88	          });
89	          await imageRepository.save(image);
90	        }
91	      }
92	
93	      for (const attributeInput of data.attributeValues) {
94	        const attribute = await this.findOrCreateAttribute(
95	          attributeRepository,
96	          attributeInput.attributeCode,
97	          attributeInput.attributeName,
98	        );
99	        const attributeValue = attributeValueRepository.create({
100	          productId: savedProduct.id,
101	          attributeId: attribute.id,
102	          value: attributeInput.value,
103	          normalizedValue: attributeInput.normalizedValue,
104	        });
105	        await attributeValueRepository.save(attributeValue);
106	      }
107	
108	      const createdProduct = await this.findByIdWithinManager(manager.getRepository(ProductEntity), savedProduct.id);
109	      return createdProduct as ProductEntity;
110	    });
111	  }
112	
113	  findCategoryById(categoryId: string): Promise<ProductCategoryEntity | null> {
114	    return this.runWithErrorLogging('findCategoryById', async () =>
115	      this.productCategoryOrmRepository.findOne({
116	        where: { id: categoryId },
117	      }),
118	    );
119	  }
120	
121	  findById(productId: string): Promise<ProductEntity | null> {
122	    return this.runWithErrorLogging('findById', async () =>
123	      this.productOrmRepository.findOne({
124	        where: { id: productId },
125	        relations: {
126	          category: true,
127	          variants: { images: true },
128	          attributeValues: { attribute: true },
129	        },
130	        order: {
131	          variants: {
132	            createdAt: 'ASC',
133	            images: {
134	              sortOrder: 'ASC',
135	              createdAt: 'ASC',
136	            },
137	          },
138	          attributeValues: {
139	            attribute: {
140	              sortOrder: 'ASC',
141	            },
142	          },
143	        },
144	      }),
145	    );
146	  }
147	
148	  findBySlug(slug: string): Promise<ProductEntity | null> {
149	    return this.runWithErrorLogging('findBySlug', async () =>
150	      this.productOrmRepository.findOne({
151	        where: { slug },
152	        relations: {
153	          category: true,
154	          variants: { images: true },
155	          attributeValues: { attribute: true },
156	        },
157	        order: {
158	          variants: {
159	            createdAt: 'ASC',
160	            images: {
161	              sortOrder: 'ASC',
162	              createdAt: 'ASC',
163	            },
164	          },
165	          attributeValues: {
166	            attribute: {
167	              sortOrder: 'ASC',
168	            },
169	          },
170	        },
171	      }),
172	    );
173	  }
174	
175	  async findByIdOrSlug(identifier: string): Promise<ProductEntity | null> {
176	    return this.runWithErrorLogging('findByIdOrSlug', async () => {
177	      const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
178	      if (uuidRegex.test(identifier)) {
179	        const byId = await this.findById(identifier);
180	        if (byId) {
181	          return byId;
182	        }
183	      }
184	
185	      return this.findBySlug(identifier);
186	    });
187	  }
188	
189	  async findMany(filters: ProductListFilters): Promise<ProductListResult> {
190	    return this.runWithErrorLogging('findMany', async () => {
191	      const qb = this.productOrmRepository
192	        .createQueryBuilder('product')
193	        .leftJoinAndSelect('product.category', 'category')
194	        .leftJoinAndSelect('product.variants', 'variant')
195	        .leftJoinAndSelect('variant.images', 'variantImage')
196	        .leftJoinAndSelect('product.attributeValues', 'attributeValue')
197	        .leftJoinAndSelect('attributeValue.attribute', 'attribute')
198	        .distinct(true);
199	
200	      this.applyFilters(qb, filters);
201	      this.applySort(qb, filters.sortBy);
202	
203	      const skip = (filters.page - 1) * filters.limit;
204	      qb.skip(skip).take(filters.limit);
205	
206	      const [items, total] = await qb.getManyAndCount();
207	      return {
208	        items,
209	        total,
210	        page: filters.page,
211	        limit: filters.limit,
212	      };
213	    });
214	  }
215	
216	  async findManyPublic(filters: ProductListFilters): Promise<ProductListResult> {
217	    // Public list endpoints generally shouldn't return full variant payloads.
218	    // We still join variants for color/size filtering, but we avoid selecting variants/images.
219	    return this.runWithErrorLogging('findManyPublic', async () => {
220	      const qb = this.productOrmRepository
221	        .createQueryBuilder('product')
222	        .leftJoinAndSelect('product.category', 'category')
223	        .leftJoin('product.variants', 'variant')
224	        .leftJoinAndSelect('product.attributeValues', 'attributeValue')
225	        .leftJoinAndSelect('attributeValue.attribute', 'attribute')
226	        .distinct(true);
227	
228	      this.applyFilters(qb, filters);
229	      this.applySort(qb, filters.sortBy);
230	
231	      const skip = (filters.page - 1) * filters.limit;
232	      qb.skip(skip).take(filters.limit);
233	
234	      const [items, total] = await qb.getManyAndCount();
235	      return {
236	        items,
237	        total,
238	        page: filters.page,
239	        limit: filters.limit,
240	      };
241	    });
242	  }
243	
244	  async findPublicFilters(): Promise<ProductFiltersResult> {
245	    return this.runWithErrorLogging('findPublicFilters', async () => {
246	      const [priceRange, categories, brands, colors, sizes, tags, attributes] = await Promise.all([
247	        this.fetchPublicPriceRange(),
248	        this.fetchPublicCategoryOptions(),
249	        this.fetchPublicBrandOptions(),
250	        this.fetchPublicColorOptions(),
251	        this.fetchPublicSizeOptions(),
252	        this.fetchPublicTagOptions(),
253	        this.fetchPublicAttributeOptions(),
254	      ]);
255	
256	      return {
257	        priceRange,
258	        categories,
259	        brands,
260	        colors,
261	        sizes,
262	        tags,
263	        attributes,
264	      };
265	    });
266	  }
267	
268	  async updateProduct(productId: string, data: ProductUpdateData): Promise<ProductEntity | null> {
269	    return this.runInTransaction('updateProduct', async (manager) => {
270	      const productRepository = manager.getRepository(ProductEntity);
271	      const variantRepository = manager.getRepository(ProductVariantEntity);
272	      const imageRepository = manager.getRepository(ProductVariantImageEntity);
273	      const attributeRepository = manager.getRepository(ProductAttributeEntity);
274	      const attributeValueRepository = manager.getRepository(ProductAttributeValueEntity);
275	
276	      const existingProduct = await productRepository.findOne({
277	        where: { id: productId },
278	      });
279	      if (!existingProduct) {
280	        return null;
281	      }
282	
283	      const updatePayload = this.removeUndefinedProperties({
284	        name: data.name,
285	        slug: data.slug,
286	        shortDescription: data.shortDescription,
287	        description: data.description,
288	        brand: data.brand,
289	        categoryId: data.categoryId,
290	        subCategory: data.subCategory,
291	        status: data.status,
292	        baseCurrency: data.baseCurrency,
293	        minPrice: data.minPrice,
294	        maxPrice: data.maxPrice,
295	        totalStock: data.totalStock,
296	        isFeatured: data.isFeatured,
297	        isActive: data.isActive,
298	        tags: data.tags,
299	        metadata: data.metadata,
300	      });
301	      if (Object.keys(updatePayload).length > 0) {
302	        const mergedProduct = productRepository.merge(existingProduct, updatePayload);
303	        await productRepository.save(mergedProduct);
304	      }
305	
306	      if (data.variants && data.replaceVariants !== false) {
307	        const existingVariants = await variantRepository.find({
308	          where: { productId },
309	          select: { id: true },
310	        });
311	        const existingVariantIds = existingVariants.map((variant) => variant.id);
312	        if (existingVariantIds.length > 0) {
313	          await imageRepository
314	            .createQueryBuilder()
315	            .delete()
316	            .where('variant_id IN (:...variantIds)', { variantIds: existingVariantIds })
317	            .execute();
318	        }
319	        await variantRepository.delete({ productId });
320	
321	        for (const variantInput of data.variants) {
322	          const variant = await variantRepository.save(
323	            variantRepository.create({
324	              productId,
325	              sku: variantInput.sku,
326	              title: variantInput.title,
327	              colorName: variantInput.colorName,
328	              colorHex: variantInput.colorHex,
329	              size: variantInput.size,
330	              price: variantInput.price,
331	              compareAtPrice: variantInput.compareAtPrice,
332	              stockQuantity: variantInput.stockQuantity,
333	              reservedQuantity: variantInput.reservedQuantity,
334	              isActive: variantInput.isActive,
335	              weightGrams: variantInput.weightGrams,
336	              barcode: variantInput.barcode,
337	              metadata: variantInput.metadata,
338	            }),
339	          );
340	
