346	              isPrimary: imageInput.isPrimary,
347	              sortOrder: imageInput.sortOrder,
348	            });
349	            await imageRepository.save(image);
350	          }
351	        }
352	      }
353	
354	      if (data.attributeValues && data.replaceAttributeValues !== false) {
355	        await attributeValueRepository.delete({ productId });
356	
357	        for (const attributeInput of data.attributeValues) {
358	          const attribute = await this.findOrCreateAttribute(
359	            attributeRepository,
360	            attributeInput.attributeCode,
361	            attributeInput.attributeName,
362	          );
363	
