440	  private applyFilters(qb: SelectQueryBuilder<ProductEntity>, filters: ProductListFilters): void {
441	    if (filters.q) {
442	      qb.andWhere(
443	        '(product.name ILIKE :query OR product.description ILIKE :query OR product.brand ILIKE :query)',
444	        {
445	          query: `%${filters.q}%`,
446	        },
447	      );
448	    }
449	
450	    if (filters.categoryId) {
451	      qb.andWhere('product.categoryId = :categoryId', { categoryId: filters.categoryId });
452	    }
453	
454	    if (filters.category) {
455	      qb.andWhere('(LOWER(category.slug) = LOWER(:category) OR LOWER(category.name) = LOWER(:category))', {
456	        category: filters.category,
457	      });
458	    }
459	
460	    if (filters.brand) {
461	      qb.andWhere('product.brand = :brand', { brand: filters.brand });
462	    }
463	
464	    if (filters.status) {
465	      qb.andWhere('product.status = :status', { status: filters.status });
466	    }
467	
468	    if (filters.isActive !== undefined) {
469	      qb.andWhere('product.isActive = :isActive', { isActive: filters.isActive });
470	    }
471	
472	    if (filters.isFeatured !== undefined) {
473	      qb.andWhere('product.isFeatured = :isFeatured', { isFeatured: filters.isFeatured });
474	    }
475	
476	    if (filters.minPrice !== undefined) {
477	      qb.andWhere('product.minPrice >= :minPrice', { minPrice: filters.minPrice });
478	    }
479	
480	    if (filters.maxPrice !== undefined) {
481	      qb.andWhere('product.maxPrice <= :maxPrice', { maxPrice: filters.maxPrice });
482	    }
483	
484	    if (filters.color) {
485	      qb.andWhere('LOWER(variant.colorName) = LOWER(:color)', { color: filters.color });
486	    }
487	
488	    if (filters.size) {
489	      qb.andWhere('LOWER(variant.size) = LOWER(:size)', { size: filters.size });
490	    }
491	
492	    if (filters.tags && filters.tags.length > 0) {
493	      filters.tags.forEach((tag, index) => {
494	        qb.andWhere(`product.tags @> ARRAY[:tag${index}]::text[]`, {
495	          [`tag${index}`]: tag,
496	        });
497	      });
498	    }
499	
500	    if (filters.attributeCode) {
501	      qb.andWhere('attribute.code = :attributeCode', {
502	        attributeCode: filters.attributeCode,
503	      });
504	    }
505	
506	    if (filters.attributeValue) {
507	      qb.andWhere('attributeValue.normalizedValue = :attributeValue', {
508	        attributeValue: filters.attributeValue,
509	      });
510	    }
511	  }
