513	  private applySort(qb: SelectQueryBuilder<ProductEntity>, sortBy: ProductSortBy): void {
514	    if (sortBy === 'priceAsc') {
515	      qb.orderBy('product.minPrice', 'ASC').addOrderBy('product.createdAt', 'DESC');
516	      return;
517	    }
518	
519	    if (sortBy === 'priceDesc') {
520	      qb.orderBy('product.maxPrice', 'DESC').addOrderBy('product.createdAt', 'DESC');
521	      return;
522	    }
523	
524	    if (sortBy === 'nameAsc') {
525	      qb.orderBy('product.name', 'ASC').addOrderBy('product.createdAt', 'DESC');
526	      return;
527	    }
528	
529	    qb.orderBy('product.createdAt', 'DESC');
530	  }
