551	  private async fetchPublicCategoryOptions(): Promise<
552	    Array<{
553	      id: string;
554	      name: string;
555	      slug: string;
556	      count: number;
557	    }>
558	  > {
559	    const rows = await this.createPublicProductsBaseQueryBuilder('product')
560	      .innerJoin('product.category', 'category')
561	      .select('category.id', 'id')
562	      .addSelect('category.name', 'name')
563	      .addSelect('category.slug', 'slug')
564	      .addSelect('COUNT(DISTINCT product.id)', 'count')
565	      .groupBy('category.id')
566	      .addGroupBy('category.name')
567	      .addGroupBy('category.slug')
568	      .orderBy('category.name', 'ASC')
569	      .getRawMany<{ id: string; name: string; slug: string; count: string }>();
570	
571	    return rows.map((row) => ({
572	      id: row.id,
573	      name: row.name,
574	      slug: row.slug,
575	      count: Number(row.count),
576	    }));
