579	  private async fetchPublicBrandOptions(): Promise<string[]> {
580	    const rows = await this.createPublicProductsBaseQueryBuilder('product')
581	      .select('DISTINCT product.brand', 'brand')
582	      .andWhere('product.brand IS NOT NULL')
583	      .andWhere("TRIM(product.brand) <> ''")
584	      .orderBy('brand', 'ASC')
585	      .getRawMany<{ brand: string }>();
