592	      .innerJoin('product.variants', 'variant')
593	      .select('DISTINCT variant.colorName', 'color')
594	      .andWhere('variant.isActive = :variantIsActive', { variantIsActive: true })
595	      .andWhere('variant.colorName IS NOT NULL')
596	      .andWhere("TRIM(variant.colorName) <> ''")
597	      .orderBy('color', 'ASC')
598	      .getRawMany<{ color: string }>();
