616	  private async fetchPublicTagOptions(): Promise<string[]> {
617	    const rows: Array<{ tag?: unknown }> = await this.productOrmRepository.query(
618	      `
619	        SELECT DISTINCT tag
620	        FROM products p
621	        CROSS JOIN LATERAL unnest(p.tags) AS tag
622	        WHERE p.status = $1
623	          AND p.is_active = $2
624	          AND trim(tag) <> ''
625	        ORDER BY tag ASC
626	      `,
627	      [ProductStatus.ACTIVE, true],
628	    );
629	
630	    return rows
631	      .map((row) => row.tag)
632	      .filter((tag): tag is string => typeof tag === 'string');
633	  }
634	
635	  private async fetchPublicAttributeOptions(): Promise<
636	    Array<{
637	      code: string;
638	      name: string;
639	      values: string[];
640	    }>
641	  > {
642	    const rows = await this.createPublicProductsBaseQueryBuilder('product')
643	      .innerJoin('product.attributeValues', 'attributeValue')
644	      .innerJoin('attributeValue.attribute', 'attribute')
645	      .select('attribute.code', 'code')
646	      .addSelect('attribute.name', 'name')
647	      .addSelect('attributeValue.value', 'value')
648	      .andWhere('attributeValue.value IS NOT NULL')
649	      .andWhere("TRIM(attributeValue.value) <> ''")
650	      .distinct(true)
651	      .orderBy('attribute.name', 'ASC')
652	      .addOrderBy('attributeValue.value', 'ASC')
653	      .getRawMany<{ code: string; name: string; value: string }>();
654	
655	    const groupedAttributes = new Map<string, { code: string; name: string; values: Set<string> }>();
656	
657	    for (const row of rows) {
658	      const existing = groupedAttributes.get(row.code);
659	      if (!existing) {
660	        groupedAttributes.set(row.code, {
661	          code: row.code,
662	          name: row.name,
663	          values: new Set([row.value]),
664	        });
665	        continue;
666	      }
667	
668	      existing.values.add(row.value);
669	    }
670	
671	    return Array.from(groupedAttributes.values()).map((attribute) => ({
672	      code: attribute.code,
673	      name: attribute.name,
674	      values: Array.from(attribute.values).sort((a, b) => a.localeCompare(b)),
675	    }));
676	  }
