678	  private removeUndefinedProperties<T extends object>(payload: T): Partial<T> {
679	    return Object.fromEntries(
680	      Object.entries(payload).filter((entry) => entry[1] !== undefined),
681	    ) as Partial<T>;
682	  }
683	
684	  private async runInTransaction<T>(
685	    operation: string,
686	    callback: (manager: EntityManager) => Promise<T>,
687	  ): Promise<T> {
688	    try {
689	      return await this.dataSource.transaction(callback);
690	    } catch (error) {
691	      this.logger.error(`Transaction failed during ${operation}`, error);
692	      throw error;
693	    }
694	  }
695	
696	  private async runWithErrorLogging<T>(operation: string, callback: () => Promise<T>): Promise<T> {
697	    try {
698	      return await callback();
699	    } catch (error) {
700	      this.logger.error(`Repository operation failed: ${operation}`, error);
701	      throw error;
702	    }
703	  }
704	}
