import { Injectable, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { DataSource, EntityManager, Repository, SelectQueryBuilder } from 'typeorm';
import { ProductStatus } from '../../../common/enums/product-status.enum';
import { ProductAttributeEntity } from '../entities/product-attribute.entity';
import { ProductAttributeValueEntity } from '../entities/product-attribute-value.entity';
import { ProductCategoryEntity } from '../entities/product-category.entity';
import { ProductEntity } from '../entities/product.entity';
import { ProductVariantImageEntity } from '../entities/product-variant-image.entity';
import { ProductVariantEntity } from '../entities/product-variant.entity';
import {
  IProductsRepository,
  ProductCreateData,
  ProductFiltersResult,
  ProductListFilters,
  ProductListResult,
  ProductSortBy,
  ProductUpdateData,
} from './products.repository.interface';

@Injectable()
export class ProductsRepository implements IProductsRepository {
  private readonly logger = new Logger(ProductsRepository.name);

  constructor(
    private readonly dataSource: DataSource,
    @InjectRepository(ProductEntity)
    private readonly productOrmRepository: Repository<ProductEntity>,
    @InjectRepository(ProductCategoryEntity)
    private readonly productCategoryOrmRepository: Repository<ProductCategoryEntity>,
  ) {}

  async createProduct(data: ProductCreateData): Promise<ProductEntity> {
    return this.runInTransaction('createProduct', async (manager) => {
      const productRepository = manager.getRepository(ProductEntity);
      const variantRepository = manager.getRepository(ProductVariantEntity);
      const imageRepository = manager.getRepository(ProductVariantImageEntity);
      const attributeRepository = manager.getRepository(ProductAttributeEntity);
      const attributeValueRepository = manager.getRepository(ProductAttributeValueEntity);

      const product = productRepository.create({
        name: data.name,
        slug: data.slug,
        shortDescription: data.shortDescription,
        description: data.description,
        brand: data.brand,
        categoryId: data.categoryId,
        subCategory: data.subCategory,
        status: data.status,
        baseCurrency: data.baseCurrency,
        minPrice: data.minPrice,
        maxPrice: data.maxPrice,
        totalStock: data.totalStock,
        isFeatured: data.isFeatured,
        isActive: data.isActive,
        tags: data.tags,
        metadata: data.metadata,
      });
      const savedProduct = await productRepository.save(product);

      for (const variantInput of data.variants) {
        const variant = await variantRepository.save(
          variantRepository.create({
            productId: savedProduct.id,
            sku: variantInput.sku,
            title: variantInput.title,
            colorName: variantInput.colorName,
            colorHex: variantInput.colorHex,
            size: variantInput.size,
            price: variantInput.price,
            compareAtPrice: variantInput.compareAtPrice,
            stockQuantity: variantInput.stockQuantity,
            reservedQuantity: variantInput.reservedQuantity,
            isActive: variantInput.isActive,
            weightGrams: variantInput.weightGrams,
            barcode: variantInput.barcode,
            metadata: variantInput.metadata,
          }),
        );

        for (const imageInput of variantInput.images) {
          const image = imageRepository.create({
            variantId: variant.id,
            imageUrl: imageInput.imageUrl,
            altText: imageInput.altText,
            isPrimary: imageInput.isPrimary,
            sortOrder: imageInput.sortOrder,
          });
          await imageRepository.save(image);
        }
      }

      for (const attributeInput of data.attributeValues) {
        const attribute = await this.findOrCreateAttribute(
          attributeRepository,
          attributeInput.attributeCode,
          attributeInput.attributeName,
        );
        const attributeValue = attributeValueRepository.create({
          productId: savedProduct.id,
          attributeId: attribute.id,
          value: attributeInput.value,
          normalizedValue: attributeInput.normalizedValue,
        });
        await attributeValueRepository.save(attributeValue);
      }

      const createdProduct = await this.findByIdWithinManager(manager.getRepository(ProductEntity), savedProduct.id);
      return createdProduct as ProductEntity;
    });
  }

  findCategoryById(categoryId: string): Promise<ProductCategoryEntity | null> {
    return this.runWithErrorLogging('findCategoryById', async () =>
      this.productCategoryOrmRepository.findOne({
        where: { id: categoryId },
      }),
    );
  }

  findById(productId: string): Promise<ProductEntity | null> {
    return this.runWithErrorLogging('findById', async () =>
      this.productOrmRepository.findOne({
        where: { id: productId },
        relations: {
          category: true,
          variants: { images: true },
          attributeValues: { attribute: true },
        },
        order: {
          variants: {
            createdAt: 'ASC',
            images: {
              sortOrder: 'ASC',
              createdAt: 'ASC',
            },
          },
          attributeValues: {
            attribute: {
              sortOrder: 'ASC',
            },
          },
        },
      }),
    );
  }

  findBySlug(slug: string): Promise<ProductEntity | null> {
    return this.runWithErrorLogging('findBySlug', async () =>
      this.productOrmRepository.findOne({
        where: { slug },
        relations: {
          category: true,
          variants: { images: true },
          attributeValues: { attribute: true },
        },
        order: {
          variants: {
            createdAt: 'ASC',
            images: {
              sortOrder: 'ASC',
              createdAt: 'ASC',
            },
          },
          attributeValues: {
            attribute: {
              sortOrder: 'ASC',
            },
          },
        },
      }),
    );
  }

  async findByIdOrSlug(identifier: string): Promise<ProductEntity | null> {
    return this.runWithErrorLogging('findByIdOrSlug', async () => {
      const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
      if (uuidRegex.test(identifier)) {
        const byId = await this.findById(identifier);
        if (byId) {
          return byId;
        }
      }

      return this.findBySlug(identifier);
    });
  }

  async findMany(filters: ProductListFilters): Promise<ProductListResult> {
    return this.runWithErrorLogging('findMany', async () => {
      const qb = this.productOrmRepository
        .createQueryBuilder('product')
        .leftJoinAndSelect('product.category', 'category')
        .leftJoinAndSelect('product.variants', 'variant')
        .leftJoinAndSelect('variant.images', 'variantImage')
        .leftJoinAndSelect('product.attributeValues', 'attributeValue')
        .leftJoinAndSelect('attributeValue.attribute', 'attribute')
        .distinct(true);

      this.applyFilters(qb, filters);
      this.applySort(qb, filters.sortBy);

      const skip = (filters.page - 1) * filters.limit;
      qb.skip(skip).take(filters.limit);

      const [items, total] = await qb.getManyAndCount();
      return {
        items,
        total,
        page: filters.page,
        limit: filters.limit,
      };
    });
  }

  async findManyPublic(filters: ProductListFilters): Promise<ProductListResult> {
    // Public list endpoints generally shouldn't return full variant payloads.
    // We still join variants for color/size filtering, but we avoid selecting variants/images.
    return this.runWithErrorLogging('findManyPublic', async () => {
      const qb = this.productOrmRepository
        .createQueryBuilder('product')
        .leftJoinAndSelect('product.category', 'category')
        .leftJoin('product.variants', 'variant')
        .leftJoinAndSelect('product.attributeValues', 'attributeValue')
        .leftJoinAndSelect('attributeValue.attribute', 'attribute')
        .distinct(true);

      this.applyFilters(qb, filters);
      this.applySort(qb, filters.sortBy);

      const skip = (filters.page - 1) * filters.limit;
      qb.skip(skip).take(filters.limit);

      const [items, total] = await qb.getManyAndCount();
      return {
        items,
        total,
        page: filters.page,
        limit: filters.limit,
      };
    });
  }

  async findPublicFilters(): Promise<ProductFiltersResult> {
    return this.runWithErrorLogging('findPublicFilters', async () => {
      const [priceRange, categories, brands, colors, sizes, tags, attributes] = await Promise.all([
        this.fetchPublicPriceRange(),
        this.fetchPublicCategoryOptions(),
        this.fetchPublicBrandOptions(),
        this.fetchPublicColorOptions(),
        this.fetchPublicSizeOptions(),
        this.fetchPublicTagOptions(),
        this.fetchPublicAttributeOptions(),
      ]);

      return {
        priceRange,
        categories,
        brands,
        colors,
        sizes,
        tags,
        attributes,
      };
    });
  }

  async updateProduct(productId: string, data: ProductUpdateData): Promise<ProductEntity | null> {
    return this.runInTransaction('updateProduct', async (manager) => {
      const productRepository = manager.getRepository(ProductEntity);
      const variantRepository = manager.getRepository(ProductVariantEntity);
      const imageRepository = manager.getRepository(ProductVariantImageEntity);
      const attributeRepository = manager.getRepository(ProductAttributeEntity);
      const attributeValueRepository = manager.getRepository(ProductAttributeValueEntity);

      const existingProduct = await productRepository.findOne({
        where: { id: productId },
      });
      if (!existingProduct) {
        return null;
      }

      const updatePayload = this.removeUndefinedProperties({
        name: data.name,
        slug: data.slug,
        shortDescription: data.shortDescription,
        description: data.description,
        brand: data.brand,
        categoryId: data.categoryId,
        subCategory: data.subCategory,
        status: data.status,
        baseCurrency: data.baseCurrency,
        minPrice: data.minPrice,
        maxPrice: data.maxPrice,
        totalStock: data.totalStock,
        isFeatured: data.isFeatured,
        isActive: data.isActive,
        tags: data.tags,
        metadata: data.metadata,
      });
      if (Object.keys(updatePayload).length > 0) {
        const mergedProduct = productRepository.merge(existingProduct, updatePayload);
        await productRepository.save(mergedProduct);
      }

      if (data.variants && data.replaceVariants !== false) {
        const existingVariants = await variantRepository.find({
          where: { productId },
          select: { id: true },
        });
        const existingVariantIds = existingVariants.map((variant) => variant.id);
        if (existingVariantIds.length > 0) {
          await imageRepository
            .createQueryBuilder()
            .delete()
            .where('variant_id IN (:...variantIds)', { variantIds: existingVariantIds })
            .execute();
        }
        await variantRepository.delete({ productId });

        for (const variantInput of data.variants) {
          const variant = await variantRepository.save(
            variantRepository.create({
              productId,
              sku: variantInput.sku,
              title: variantInput.title,
              colorName: variantInput.colorName,
              colorHex: variantInput.colorHex,
              size: variantInput.size,
              price: variantInput.price,
              compareAtPrice: variantInput.compareAtPrice,
              stockQuantity: variantInput.stockQuantity,
              reservedQuantity: variantInput.reservedQuantity,
              isActive: variantInput.isActive,
              weightGrams: variantInput.weightGrams,
              barcode: variantInput.barcode,
              metadata: variantInput.metadata,
            }),
          );

          for (const imageInput of variantInput.images) {
            const image = imageRepository.create({
              variantId: variant.id,
              imageUrl: imageInput.imageUrl,
              altText: imageInput.altText,
              isPrimary: imageInput.isPrimary,
              sortOrder: imageInput.sortOrder,
            });
            await imageRepository.save(image);
          }
        }
      }

      if (data.attributeValues && data.replaceAttributeValues !== false) {
        await attributeValueRepository.delete({ productId });

        for (const attributeInput of data.attributeValues) {
          const attribute = await this.findOrCreateAttribute(
            attributeRepository,
            attributeInput.attributeCode,
            attributeInput.attributeName,
          );

          const attributeValue = attributeValueRepository.create({
            productId,
            attributeId: attribute.id,
            value: attributeInput.value,
            normalizedValue: attributeInput.normalizedValue,
          });
          await attributeValueRepository.save(attributeValue);
        }
      }

      return this.findByIdWithinManager(productRepository, productId);
    });
  }

  async deleteById(productId: string): Promise<boolean> {
    return this.runInTransaction('deleteById', async (manager) => {
      const productRepository = manager.getRepository(ProductEntity);
      const result = await productRepository.delete({ id: productId });
      return (result.affected ?? 0) > 0;
    });
  }

  private async findOrCreateAttribute(
    attributeRepository: Repository<ProductAttributeEntity>,
    code: string,
    name: string | null,
  ): Promise<ProductAttributeEntity> {
    const existing = await attributeRepository.findOne({ where: { code } });
    if (existing) {
      return existing;
    }

    const created = attributeRepository.create({
      code,
      name: name ?? this.humanizeAttributeCode(code),
      isFilterable: true,
    });
    return attributeRepository.save(created);
  }

  private humanizeAttributeCode(code: string): string {
    return code
      .split('-')
      .filter(Boolean)
      .map((token) => token.charAt(0).toUpperCase() + token.slice(1))
      .join(' ');
  }

  private async findByIdWithinManager(
    repository: Repository<ProductEntity>,
    productId: string,
  ): Promise<ProductEntity | null> {
    return repository.findOne({
      where: { id: productId },
      relations: {
        category: true,
        variants: { images: true },
        attributeValues: { attribute: true },
      },
      order: {
        variants: {
          createdAt: 'ASC',
          images: {
            sortOrder: 'ASC',
            createdAt: 'ASC',
          },
        },
        attributeValues: {
          attribute: {
            sortOrder: 'ASC',
          },
        },
      },
    });
  }

  private applyFilters(qb: SelectQueryBuilder<ProductEntity>, filters: ProductListFilters): void {
    if (filters.q) {
      qb.andWhere(
        '(product.name ILIKE :query OR product.description ILIKE :query OR product.brand ILIKE :query)',
        {
          query: `%${filters.q}%`,
        },
      );
    }

    if (filters.categoryId) {
      qb.andWhere('product.categoryId = :categoryId', { categoryId: filters.categoryId });
    }

    if (filters.category) {
      qb.andWhere('(LOWER(category.slug) = LOWER(:category) OR LOWER(category.name) = LOWER(:category))', {
        category: filters.category,
      });
    }

    if (filters.brand) {
      qb.andWhere('product.brand = :brand', { brand: filters.brand });
    }

    if (filters.status) {
      qb.andWhere('product.status = :status', { status: filters.status });
    }

    if (filters.isActive !== undefined) {
      qb.andWhere('product.isActive = :isActive', { isActive: filters.isActive });
    }

    if (filters.isFeatured !== undefined) {
      qb.andWhere('product.isFeatured = :isFeatured', { isFeatured: filters.isFeatured });
    }

    if (filters.minPrice !== undefined) {
      qb.andWhere('product.minPrice >= :minPrice', { minPrice: filters.minPrice });
    }

    if (filters.maxPrice !== undefined) {
      qb.andWhere('product.maxPrice <= :maxPrice', { maxPrice: filters.maxPrice });
    }

    if (filters.color) {
      qb.andWhere('LOWER(variant.colorName) = LOWER(:color)', { color: filters.color });
    }

    if (filters.size) {
      qb.andWhere('LOWER(variant.size) = LOWER(:size)', { size: filters.size });
    }

    if (filters.tags && filters.tags.length > 0) {
      filters.tags.forEach((tag, index) => {
        qb.andWhere(`product.tags @> ARRAY[:tag${index}]::text[]`, {
          [`tag${index}`]: tag,
        });
      });
    }

    if (filters.attributeCode) {
      qb.andWhere('attribute.code = :attributeCode', {
        attributeCode: filters.attributeCode,
      });
    }

    if (filters.attributeValue) {
      qb.andWhere('attributeValue.normalizedValue = :attributeValue', {
        attributeValue: filters.attributeValue,
      });
    }
  }

  private applySort(qb: SelectQueryBuilder<ProductEntity>, sortBy: ProductSortBy): void {
    if (sortBy === 'priceAsc') {
      qb.orderBy('product.minPrice', 'ASC').addOrderBy('product.createdAt', 'DESC');
      return;
    }

    if (sortBy === 'priceDesc') {
      qb.orderBy('product.maxPrice', 'DESC').addOrderBy('product.createdAt', 'DESC');
      return;
    }

    if (sortBy === 'nameAsc') {
      qb.orderBy('product.name', 'ASC').addOrderBy('product.createdAt', 'DESC');
      return;
    }

    qb.orderBy('product.createdAt', 'DESC');
  }

  private createPublicProductsBaseQueryBuilder(alias = 'product'): SelectQueryBuilder<ProductEntity> {
    return this.productOrmRepository
      .createQueryBuilder(alias)
      .where(`${alias}.status = :status`, { status: ProductStatus.ACTIVE })
      .andWhere(`${alias}.isActive = :isActive`, { isActive: true });
  }

  private async fetchPublicPriceRange(): Promise<{ min: string; max: string }> {
    const raw = await this.createPublicProductsBaseQueryBuilder('product')
      .select('MIN(product.minPrice)', 'min')
      .addSelect('MAX(product.maxPrice)', 'max')
      .getRawOne<{ min: string | null; max: string | null }>();

    return {
      min: raw?.min ?? '0.00',
      max: raw?.max ?? '0.00',
    };
  }

  private async fetchPublicCategoryOptions(): Promise<
    Array<{
      id: string;
      name: string;
      slug: string;
      count: number;
    }>
  > {
    const rows = await this.createPublicProductsBaseQueryBuilder('product')
      .innerJoin('product.category', 'category')
      .select('category.id', 'id')
      .addSelect('category.name', 'name')
      .addSelect('category.slug', 'slug')
      .addSelect('COUNT(DISTINCT product.id)', 'count')
      .groupBy('category.id')
      .addGroupBy('category.name')
      .addGroupBy('category.slug')
      .orderBy('category.name', 'ASC')
      .getRawMany<{ id: string; name: string; slug: string; count: string }>();

    return rows.map((row) => ({
      id: row.id,
      name: row.name,
      slug: row.slug,
      count: Number(row.count),
    }));
  }

  private async fetchPublicBrandOptions(): Promise<string[]> {
    const rows = await this.createPublicProductsBaseQueryBuilder('product')
      .select('DISTINCT product.brand', 'brand')
      .andWhere('product.brand IS NOT NULL')
      .andWhere("TRIM(product.brand) <> ''")
      .orderBy('brand', 'ASC')
      .getRawMany<{ brand: string }>();

    return rows.map((row) => row.brand);
  }

  private async fetchPublicColorOptions(): Promise<string[]> {
    const rows = await this.createPublicProductsBaseQueryBuilder('product')
      .innerJoin('product.variants', 'variant')
      .select('DISTINCT variant.colorName', 'color')
      .andWhere('variant.isActive = :variantIsActive', { variantIsActive: true })
      .andWhere('variant.colorName IS NOT NULL')
      .andWhere("TRIM(variant.colorName) <> ''")
      .orderBy('color', 'ASC')
      .getRawMany<{ color: string }>();

    return rows.map((row) => row.color);
  }

  private async fetchPublicSizeOptions(): Promise<string[]> {
    const rows = await this.createPublicProductsBaseQueryBuilder('product')
      .innerJoin('product.variants', 'variant')
      .select('DISTINCT variant.size', 'size')
      .andWhere('variant.isActive = :variantIsActive', { variantIsActive: true })
      .andWhere('variant.size IS NOT NULL')
      .andWhere("TRIM(variant.size) <> ''")
      .orderBy('size', 'ASC')
      .getRawMany<{ size: string }>();

    return rows.map((row) => row.size);
  }

  private async fetchPublicTagOptions(): Promise<string[]> {
    const rows: Array<{ tag?: unknown }> = await this.productOrmRepository.query(
      `
        SELECT DISTINCT tag
        FROM products p
        CROSS JOIN LATERAL unnest(p.tags) AS tag
        WHERE p.status = $1
          AND p.is_active = $2
          AND trim(tag) <> ''
        ORDER BY tag ASC
      `,
      [ProductStatus.ACTIVE, true],
    );

    return rows
      .map((row) => row.tag)
      .filter((tag): tag is string => typeof tag === 'string');
  }

  private async fetchPublicAttributeOptions(): Promise<
    Array<{
      code: string;
      name: string;
      values: string[];
    }>
  > {
    const rows = await this.createPublicProductsBaseQueryBuilder('product')
      .innerJoin('product.attributeValues', 'attributeValue')
      .innerJoin('attributeValue.attribute', 'attribute')
      .select('attribute.code', 'code')
      .addSelect('attribute.name', 'name')
      .addSelect('attributeValue.value', 'value')
      .andWhere('attributeValue.value IS NOT NULL')
      .andWhere("TRIM(attributeValue.value) <> ''")
      .distinct(true)
      .orderBy('attribute.name', 'ASC')
      .addOrderBy('attributeValue.value', 'ASC')
      .getRawMany<{ code: string; name: string; value: string }>();

    const groupedAttributes = new Map<string, { code: string; name: string; values: Set<string> }>();

    for (const row of rows) {
      const existing = groupedAttributes.get(row.code);
      if (!existing) {
        groupedAttributes.set(row.code, {
          code: row.code,
          name: row.name,
          values: new Set([row.value]),
        });
        continue;
      }

      existing.values.add(row.value);
    }

    return Array.from(groupedAttributes.values()).map((attribute) => ({
      code: attribute.code,
      name: attribute.name,
      values: Array.from(attribute.values).sort((a, b) => a.localeCompare(b)),
    }));
  }

  private removeUndefinedProperties<T extends object>(payload: T): Partial<T> {
    return Object.fromEntries(
      Object.entries(payload).filter((entry) => entry[1] !== undefined),
    ) as Partial<T>;
  }

  private async runInTransaction<T>(
    operation: string,
    callback: (manager: EntityManager) => Promise<T>,
  ): Promise<T> {
    try {
      return await this.dataSource.transaction(callback);
    } catch (error) {
      this.logger.error(`Transaction failed during ${operation}`, error);
      throw error;
    }
  }

  private async runWithErrorLogging<T>(operation: string, callback: () => Promise<T>): Promise<T> {
    try {
      return await callback();
    } catch (error) {
      this.logger.error(`Repository operation failed: ${operation}`, error);
      throw error;
    }
  }
}

