import {
  Body,
  Controller,
  Delete,
  Get,
  HttpCode,
  HttpStatus,
  Param,
  Patch,
  Post,
  Query,
} from '@nestjs/common';
import {
  ApiBearerAuth,
  ApiCreatedResponse,
  ApiNoContentResponse,
  ApiOkResponse,
  ApiOperation,
  ApiParam,
  ApiQuery,
  ApiTags,
} from '@nestjs/swagger';
import { Public } from '../../../common/decorators/public.decorator';
import { Roles } from '../../../common/decorators/roles.decorator';
import { Role } from '../../../common/enums/role.enum';
import { CreateProductDto } from '../dtos/create-product.dto';
import { ProductFiltersResponseDto } from '../dtos/product-filters-response.dto';
import { ListProductsQueryDto } from '../dtos/list-products-query.dto';
import { ProductIdentifierParamsDto } from '../dtos/product-identifier-params.dto';
import { ProductResponseDto } from '../dtos/product-response.dto';
import { ProductsListResponseDto } from '../dtos/products-list-response.dto';
import { UpdateProductDto } from '../dtos/update-product.dto';
import { ProductsService } from '../services/products.service';

@ApiTags('Products')
@Controller('products')
export class ProductsController {
  constructor(private readonly productsService: ProductsService) {}

  @Public()
  @Get()
  @ApiOperation({ summary: 'Browse active products with filters and pagination' })
  @ApiQuery({ name: 'page', required: false, type: Number })
  @ApiQuery({ name: 'limit', required: false, type: Number })
  @ApiOkResponse({ type: ProductsListResponseDto })
  async findPublicProducts(@Query() query: ListProductsQueryDto): Promise<ProductsListResponseDto> {
    const result = await this.productsService.findPublic(query);
    return ProductsListResponseDto.fromPaginatedResult(result);
  }

  @Post()
  @Roles(Role.ADMIN)
  @ApiBearerAuth('access-token')
  @ApiOperation({ summary: 'Create a product with variants/images (restricted access)' })
  @ApiCreatedResponse({ type: ProductResponseDto })
  async createProduct(@Body() dto: CreateProductDto): Promise<ProductResponseDto> {
    const product = await this.productsService.create(dto);
    return ProductResponseDto.fromEntity(product);
  }

  @Get('all')
  @Roles(Role.ADMIN)
  @ApiBearerAuth('access-token')
  @ApiOperation({ summary: 'List all products (supports inactive items)' })
  @ApiOkResponse({ type: ProductsListResponseDto })
  async findAdminProducts(@Query() query: ListProductsQueryDto): Promise<ProductsListResponseDto> {
    const result = await this.productsService.findAdmin(query);
    return ProductsListResponseDto.fromPaginatedResult(result);
  }

  @Public()
  @Get('filters')
  @ApiOperation({ summary: 'Get available product filters for storefront' })
  @ApiOkResponse({ type: ProductFiltersResponseDto })
  async findPublicProductFilters(): Promise<ProductFiltersResponseDto> {
    const filters = await this.productsService.findPublicFilters();
    return ProductFiltersResponseDto.fromResult(filters);
  }

  @Get(':identifier/internal')
  @Roles(Role.ADMIN)
  @ApiBearerAuth('access-token')
  @ApiOperation({ summary: 'Get one product by id or slug (restricted access)' })
  @ApiParam({ name: 'identifier', description: 'Product UUID or slug' })
  @ApiOkResponse({ type: ProductResponseDto })
  async findAdminProductByIdentifier(
    @Param() params: ProductIdentifierParamsDto,
  ): Promise<ProductResponseDto> {
    const product = await this.productsService.findAdminByIdentifierOrFail(params.identifier);
    return ProductResponseDto.fromEntity(product);
  }

  @Patch(':identifier')
  @Roles(Role.ADMIN)
  @ApiBearerAuth('access-token')
  @ApiOperation({ summary: 'Update one product by id or slug (restricted access)' })
  @ApiParam({ name: 'identifier', description: 'Product UUID or slug' })
  @ApiOkResponse({ type: ProductResponseDto })
  async updateProduct(
    @Param() params: ProductIdentifierParamsDto,
    @Body() dto: UpdateProductDto,
  ): Promise<ProductResponseDto> {
    const product = await this.productsService.updateByIdentifier(params.identifier, dto);
    return ProductResponseDto.fromEntity(product);
  }

  @Delete(':identifier')
  @Roles(Role.ADMIN)
  @ApiBearerAuth('access-token')
  @HttpCode(HttpStatus.NO_CONTENT)
  @ApiOperation({ summary: 'Delete one product by id or slug (restricted access)' })
  @ApiParam({ name: 'identifier', description: 'Product UUID or slug' })
  @ApiNoContentResponse()
  async deleteProduct(@Param() params: ProductIdentifierParamsDto): Promise<void> {
    await this.productsService.deleteByIdentifier(params.identifier);
  }

  @Public()
  @Get(':identifier')
  @ApiOperation({ summary: 'Get one active product by id or slug' })
  @ApiParam({ name: 'identifier', description: 'Product UUID or slug' })
  @ApiOkResponse({ type: ProductResponseDto })
  async findPublicProductByIdentifier(
    @Param() params: ProductIdentifierParamsDto,
  ): Promise<ProductResponseDto> {
    const product = await this.productsService.findPublicByIdentifierOrFail(params.identifier);
    return ProductResponseDto.fromEntity(product);
  }
}

