import { ApiProperty, ApiPropertyOptional } from '@nestjs/swagger';
import type { ProductStatus } from '../../../common/enums/product-status.enum';
import type { ProductEntity } from '../entities/product.entity';
import { ProductAttributeValueResponseDto } from './product-attribute-value-response.dto';
import { ProductCategoryResponseDto } from './product-category-response.dto';
import { ProductVariantResponseDto } from './product-variant-response.dto';

export class ProductResponseDto {
  @ApiProperty({
    format: 'uuid',
    example: '4c47dd03-2dad-4f7a-bdd4-4c2d8f4a5a6f',
  })
  id!: string;

  @ApiProperty({
    example: 'Premium Running Sneakers',
  })
  name!: string;

  @ApiProperty({
    example: 'premium-running-sneakers',
  })
  slug!: string;

  @ApiProperty({
    example: 'Lightweight all-day comfort sneakers',
    nullable: true,
  })
  shortDescription!: string | null;

  @ApiProperty({
    example: 'Engineered for long-distance comfort with breathable fabric.',
    nullable: true,
  })
  description!: string | null;

  @ApiProperty({
    example: 'Nike',
    nullable: true,
  })
  brand!: string | null;

  @ApiProperty({
    format: 'uuid',
    example: '7dfd2ebb-cd6f-48a4-a74e-f46a9f90de9d',
  })
  categoryId!: string;

  @ApiProperty({
    type: () => ProductCategoryResponseDto,
  })
  category!: ProductCategoryResponseDto;

  @ApiProperty({
    example: 'Running Shoes',
    nullable: true,
  })
  subCategory!: string | null;

  @ApiProperty({
    example: 'active',
  })
  status!: ProductStatus;

  @ApiProperty({
    example: 'USD',
  })
  baseCurrency!: string;

  @ApiProperty({
    example: '1499.00',
  })
  minPrice!: string;

  @ApiProperty({
    example: '2499.00',
  })
  maxPrice!: string;

  @ApiProperty({
    example: 240,
  })
  totalStock!: number;

  @ApiProperty({
    example: false,
  })
  isFeatured!: boolean;

  @ApiProperty({
    example: true,
  })
  isActive!: boolean;

  @ApiProperty({
    example: '4.60',
    nullable: true,
  })
  ratingAverage!: string | null;

  @ApiProperty({
    example: 124,
  })
  ratingCount!: number;

  @ApiProperty({
    type: [String],
    example: ['sports', 'running'],
  })
  tags!: string[];

  @ApiProperty({
    type: Object,
    nullable: true,
  })
  metadata!: Record<string, unknown> | null;

  @ApiPropertyOptional({
    type: () => [ProductVariantResponseDto],
  })
  variants?: ProductVariantResponseDto[];

  @ApiProperty({
    type: () => [ProductAttributeValueResponseDto],
  })
  attributeValues!: ProductAttributeValueResponseDto[];

  @ApiProperty({
    type: String,
    format: 'date-time',
  })
  createdAt!: Date;

  @ApiProperty({
    type: String,
    format: 'date-time',
  })
  updatedAt!: Date;

  static fromEntity(entity: ProductEntity): ProductResponseDto {
    return {
      id: entity.id,
      name: entity.name,
      slug: entity.slug,
      shortDescription: entity.shortDescription,
      description: entity.description,
      brand: entity.brand,
      categoryId: entity.categoryId,
      category: ProductCategoryResponseDto.fromEntity(entity.category),
      subCategory: entity.subCategory,
      status: entity.status,
      baseCurrency: entity.baseCurrency,
      minPrice: entity.minPrice,
      maxPrice: entity.maxPrice,
      totalStock: entity.totalStock,
      isFeatured: entity.isFeatured,
      isActive: entity.isActive,
      ratingAverage: entity.ratingAverage,
      ratingCount: entity.ratingCount,
      tags: entity.tags,
      metadata: entity.metadata,
      ...(Array.isArray(entity.variants) && entity.variants.length > 0
        ? {
            variants: entity.variants.map((variant) => ProductVariantResponseDto.fromEntity(variant)),
          }
        : {}),
      attributeValues: (entity.attributeValues ?? []).map((attributeValue) =>
        ProductAttributeValueResponseDto.fromEntity(attributeValue),
      ),
      createdAt: entity.createdAt,
      updatedAt: entity.updatedAt,
    };
  }
}

