import { ApiProperty } from '@nestjs/swagger';
import type { ProductEntity } from '../entities/product.entity';
import { ProductResponseDto } from './product-response.dto';

export class ProductsListResponseDto {
  @ApiProperty({
    example: 124,
  })
  total!: number;

  @ApiProperty({
    example: 1,
  })
  page!: number;

  @ApiProperty({
    example: 20,
  })
  limit!: number;

  @ApiProperty({
    example: 7,
    description: 'Total pages based on total and limit',
  })
  totalPages!: number;

  @ApiProperty({
    type: () => [ProductResponseDto],
  })
  items!: ProductResponseDto[];

  static fromPaginatedResult(params: {
    items: ProductEntity[];
    total: number;
    page: number;
    limit: number;
  }): ProductsListResponseDto {
    return {
      total: params.total,
      page: params.page,
      limit: params.limit,
      totalPages: Math.ceil(params.total / params.limit),
      items: params.items.map((item) => ProductResponseDto.fromEntity(item)),
    };
  }
}

