import {
  BadRequestException,
  HttpException,
  Inject,
  Injectable,
  InternalServerErrorException,
  Logger,
  NotFoundException,
} from '@nestjs/common';
import { QueryFailedError } from 'typeorm';
import { ProductStatus } from '../../../common/enums/product-status.enum';
import { CreateProductAttributeValueDto } from '../dtos/create-product-attribute-value.dto';
import { CreateProductDto } from '../dtos/create-product.dto';
import { CreateProductVariantDto } from '../dtos/create-product-variant.dto';
import { ListProductsQueryDto } from '../dtos/list-products-query.dto';
import { UpdateProductDto } from '../dtos/update-product.dto';
import { ProductEntity } from '../entities/product.entity';
import {
  IProductsRepository,
  PRODUCTS_REPOSITORY,
  ProductAttributeValueUpsertData,
  ProductCreateData,
  ProductFiltersResult,
  ProductListFilters,
  ProductUpdateData,
  ProductVariantImageUpsertData,
  ProductVariantUpsertData,
} from '../repositories/products.repository.interface';

@Injectable()
export class ProductsService {
  private readonly logger = new Logger(ProductsService.name);

  constructor(
    @Inject(PRODUCTS_REPOSITORY)
    private readonly productsRepository: IProductsRepository,
  ) {}

  create(dto: CreateProductDto): Promise<ProductEntity> {
    return this.runWithErrorHandling('create product', async () => {
      this.validateVariantPayload(dto.variants);
      await this.ensureCategoryExists(dto.categoryId);

      const variantData = dto.variants.map((variant) => this.mapVariantUpsertData(variant));
      const attributeValues = (dto.attributeValues ?? []).map((attribute) =>
        this.mapAttributeValueUpsertData(attribute),
      );
      const inventorySummary = this.computeInventorySummary(variantData);

      const payload: ProductCreateData = {
        name: this.normalizeText(dto.name),
        slug: this.normalizeSlug(dto.slug),
        shortDescription: this.normalizeNullableText(dto.shortDescription),
        description: this.normalizeNullableText(dto.description),
        brand: this.normalizeNullableText(dto.brand),
        categoryId: dto.categoryId,
        subCategory: this.normalizeNullableText(dto.subCategory),
        status: dto.status ?? ProductStatus.DRAFT,
        baseCurrency: (dto.baseCurrency ?? 'USD').toUpperCase(),
        isFeatured: dto.isFeatured ?? false,
        isActive: dto.isActive ?? true,
        tags: this.normalizeTags(dto.tags ?? []),
        metadata: dto.metadata ?? null,
        minPrice: inventorySummary.minPrice,
        maxPrice: inventorySummary.maxPrice,
        totalStock: inventorySummary.totalStock,
        variants: variantData,
        attributeValues,
      };

      return this.productsRepository.createProduct(payload);
    });
  }

  async findPublicByIdentifierOrFail(identifier: string): Promise<ProductEntity> {
    return this.runWithErrorHandling('fetch product', async () => {
      const product = await this.productsRepository.findByIdOrSlug(identifier);
      if (!product || !product.isActive || product.status !== ProductStatus.ACTIVE) {
        throw new NotFoundException('Product not found');
      }
      return product;
    });
  }

  findPublic(query: ListProductsQueryDto): Promise<{
    items: ProductEntity[];
    total: number;
    page: number;
    limit: number;
  }> {
    return this.runWithErrorHandling('fetch products', async () =>
      this.productsRepository.findManyPublic({
        ...this.mapListFilters(query),
        status: ProductStatus.ACTIVE,
        isActive: true,
      }),
    );
  }

  findPublicFilters(): Promise<ProductFiltersResult> {
    return this.runWithErrorHandling('fetch product filters', async () =>
      this.productsRepository.findPublicFilters(),
    );
  }

  async findAdminByIdentifierOrFail(identifier: string): Promise<ProductEntity> {
    return this.runWithErrorHandling('fetch admin product', async () => {
      const product = await this.productsRepository.findByIdOrSlug(identifier);
      if (!product) {
        throw new NotFoundException('Product not found');
      }
      return product;
    });
  }

  async findAdmin(query: ListProductsQueryDto): Promise<{
    items: ProductEntity[];
    total: number;
    page: number;
    limit: number;
  }> {
    try {
      const filters: ProductListFilters = {
        ...this.mapListFilters(query),
        isActive: query.includeInactive ? undefined : true,
      };
      return await this.productsRepository.findMany(filters);
    } catch (error) {
      if (error instanceof HttpException) {
        throw error;
      }

      this.logger.error('Unexpected error while trying to fetch admin products', error);
      throw new InternalServerErrorException('Unable to fetch admin products right now');
    }
  }

  async updateByIdentifier(identifier: string, dto: UpdateProductDto): Promise<ProductEntity> {
    return this.runWithErrorHandling('update product', async () => {
      const existing = await this.productsRepository.findByIdOrSlug(identifier);
      if (!existing) {
        throw new NotFoundException('Product not found');
      }

      const variantData = dto.variants?.map((variant) => this.mapVariantUpsertData(variant));
      if (variantData) {
        this.validateVariantPayload(dto.variants ?? []);
      }
      const attributeValues = dto.attributeValues?.map((attribute) =>
        this.mapAttributeValueUpsertData(attribute),
      );

      const hasAnyRootField = this.hasAnyDefinedField(dto, [
        'name',
        'slug',
        'shortDescription',
        'description',
        'brand',
        'categoryId',
        'subCategory',
        'status',
        'baseCurrency',
        'isFeatured',
        'isActive',
        'tags',
        'metadata',
        'variants',
        'attributeValues',
      ]);
      if (!hasAnyRootField) {
        throw new BadRequestException('At least one field must be provided for update');
      }

      const updatePayload: ProductUpdateData = {
        name: dto.name ? this.normalizeText(dto.name) : undefined,
        slug: dto.slug ? this.normalizeSlug(dto.slug) : undefined,
        shortDescription:
          dto.shortDescription !== undefined ? this.normalizeNullableText(dto.shortDescription) : undefined,
        description: dto.description !== undefined ? this.normalizeNullableText(dto.description) : undefined,
        brand: dto.brand !== undefined ? this.normalizeNullableText(dto.brand) : undefined,
        categoryId: dto.categoryId,
        subCategory:
          dto.subCategory !== undefined ? this.normalizeNullableText(dto.subCategory) : undefined,
        status: dto.status,
        baseCurrency: dto.baseCurrency ? dto.baseCurrency.toUpperCase() : undefined,
        isFeatured: dto.isFeatured,
        isActive: dto.isActive,
        tags: dto.tags ? this.normalizeTags(dto.tags) : undefined,
        metadata: dto.metadata !== undefined ? (dto.metadata ?? null) : undefined,
        variants: variantData,
        attributeValues,
        replaceVariants: dto.replaceVariants ?? true,
        replaceAttributeValues: dto.replaceAttributeValues ?? true,
      };

      if (variantData && updatePayload.replaceVariants !== false) {
        const inventorySummary = this.computeInventorySummary(variantData);
        updatePayload.minPrice = inventorySummary.minPrice;
        updatePayload.maxPrice = inventorySummary.maxPrice;
        updatePayload.totalStock = inventorySummary.totalStock;
      }

      if (updatePayload.categoryId) {
        await this.ensureCategoryExists(updatePayload.categoryId);
      }

      const updated = await this.productsRepository.updateProduct(existing.id, updatePayload);
      if (!updated) {
        throw new NotFoundException('Product not found');
      }
      return updated;
    });
  }

  async deleteByIdentifier(identifier: string): Promise<void> {
    await this.runWithErrorHandling('delete product', async () => {
      const existing = await this.productsRepository.findByIdOrSlug(identifier);
      if (!existing) {
        throw new NotFoundException('Product not found');
      }
      const deleted = await this.productsRepository.deleteById(existing.id);
      if (!deleted) {
        throw new NotFoundException('Product not found');
      }
    });
  }

  private mapListFilters(query: ListProductsQueryDto): ProductListFilters {
    if (
      query.minPrice !== undefined &&
      query.maxPrice !== undefined &&
      query.minPrice > query.maxPrice
    ) {
      throw new BadRequestException('minPrice cannot be greater than maxPrice');
    }

    return {
      q: query.q?.trim() || undefined,
      categoryId: query.categoryId,
      category: query.category?.trim() || undefined,
      brand: query.brand?.trim() || undefined,
      status: query.status,
      isFeatured: query.isFeatured,
      minPrice: query.minPrice,
      maxPrice: query.maxPrice,
      color: query.color?.trim() || undefined,
      size: query.size?.trim() || undefined,
      tags: query.tags?.map((tag) => tag.trim()).filter(Boolean),
      attributeCode: query.attributeCode?.trim().toLowerCase() || undefined,
      attributeValue: query.attributeValue?.trim().toLowerCase() || undefined,
      page: query.page ?? 1,
      limit: query.limit ?? 20,
      sortBy: query.sortBy ?? 'newest',
    };
  }

  private mapVariantUpsertData(dto: CreateProductVariantDto): ProductVariantUpsertData {
    if (dto.compareAtPrice !== undefined && dto.compareAtPrice !== null && dto.compareAtPrice < dto.price) {
      throw new BadRequestException(`compareAtPrice must be greater than or equal to price for SKU ${dto.sku}`);
    }
    if ((dto.reservedQuantity ?? 0) > dto.stockQuantity) {
      throw new BadRequestException(
        `reservedQuantity cannot be greater than stockQuantity for SKU ${dto.sku}`,
      );
    }

    const images = dto.images.map((image) => this.mapVariantImageUpsertData(image));
    const primaryImageCount = images.filter((image) => image.isPrimary).length;
    if (primaryImageCount > 1) {
      throw new BadRequestException(`Only one primary image is allowed per variant for SKU ${dto.sku}`);
    }
    if (primaryImageCount === 0 && images.length > 0) {
      images[0].isPrimary = true;
    }

    return {
      sku: this.normalizeText(dto.sku),
      title: this.normalizeNullableText(dto.title),
      colorName: this.normalizeNullableText(dto.colorName),
      colorHex: dto.colorHex ? dto.colorHex.toUpperCase() : null,
      size: this.normalizeNullableText(dto.size),
      price: this.numberToMoneyString(dto.price),
      compareAtPrice:
        dto.compareAtPrice !== undefined && dto.compareAtPrice !== null
          ? this.numberToMoneyString(dto.compareAtPrice)
          : null,
      stockQuantity: dto.stockQuantity,
      reservedQuantity: dto.reservedQuantity ?? 0,
      isActive: dto.isActive ?? true,
      weightGrams: dto.weightGrams ?? null,
      barcode: this.normalizeNullableText(dto.barcode),
      metadata: dto.metadata ?? null,
      images,
    };
  }

  private mapVariantImageUpsertData(image: {
    imageUrl: string;
    altText?: string | null;
    isPrimary?: boolean;
    sortOrder?: number;
  }): ProductVariantImageUpsertData {
    return {
      imageUrl: image.imageUrl.trim(),
      altText: this.normalizeNullableText(image.altText),
      isPrimary: image.isPrimary ?? false,
      sortOrder: image.sortOrder ?? 0,
    };
  }

  private mapAttributeValueUpsertData(
    dto: CreateProductAttributeValueDto,
  ): ProductAttributeValueUpsertData {
    const code = this.normalizeAttributeCode(dto.attributeCode);
    const rawValue = this.normalizeText(dto.value);
    return {
      attributeCode: code,
      attributeName: this.normalizeNullableText(dto.attributeName),
      value: rawValue,
      normalizedValue: rawValue.toLowerCase(),
    };
  }

  private validateVariantPayload(variants: CreateProductVariantDto[]): void {
    const uniqueSkus = new Set<string>();
    const normalizedColorSizeKeys = new Set<string>();

    for (const variant of variants) {
      const sku = this.normalizeText(variant.sku).toLowerCase();
      if (uniqueSkus.has(sku)) {
        throw new BadRequestException(`Duplicate SKU found in payload: ${variant.sku}`);
      }
      uniqueSkus.add(sku);

      const color = (variant.colorName ?? '').trim().toLowerCase();
      const size = (variant.size ?? '').trim().toLowerCase();
      const colorSizeKey = `${color}::${size}`;
      if (color || size) {
        if (normalizedColorSizeKeys.has(colorSizeKey)) {
          throw new BadRequestException(
            `Duplicate variant combination for color "${variant.colorName ?? '-'}" and size "${variant.size ?? '-'}"`,
          );
        }
        normalizedColorSizeKeys.add(colorSizeKey);
      }
    }
  }

  private computeInventorySummary(variants: ProductVariantUpsertData[]): {
    minPrice: string;
    maxPrice: string;
    totalStock: number;
  } {
    const activeVariants = variants.filter((variant) => variant.isActive);
    const sourceVariants = activeVariants.length > 0 ? activeVariants : variants;
    const prices = sourceVariants.map((variant) => Number(variant.price));
    const minPrice = Math.min(...prices);
    const maxPrice = Math.max(...prices);
    const totalStock = sourceVariants.reduce((sum, variant) => sum + variant.stockQuantity, 0);

    return {
      minPrice: this.numberToMoneyString(minPrice),
      maxPrice: this.numberToMoneyString(maxPrice),
      totalStock,
    };
  }

  private normalizeText(value: string): string {
    return value.trim();
  }

  private normalizeNullableText(value?: string | null): string | null {
    if (value === undefined || value === null) {
      return null;
    }
    const trimmed = value.trim();
    return trimmed.length > 0 ? trimmed : null;
  }

  private normalizeSlug(slug: string): string {
    return slug.trim().toLowerCase();
  }

  private normalizeAttributeCode(code: string): string {
    return code
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-+|-+$/g, '');
  }

  private normalizeTags(tags: string[]): string[] {
    return Array.from(
      new Set(
        tags
          .map((tag) => tag.trim().toLowerCase())
          .filter((tag) => tag.length > 0),
      ),
    );
  }

  private numberToMoneyString(value: number): string {
    return value.toFixed(2);
  }

  private async ensureCategoryExists(categoryId: string): Promise<void> {
    const category = await this.productsRepository.findCategoryById(categoryId);
    if (!category || !category.isActive) {
      throw new BadRequestException('Invalid or inactive categoryId');
    }
  }

  private hasAnyDefinedField<T extends object>(payload: T, fields: Array<keyof T>): boolean {
    return fields.some((field) => payload[field] !== undefined);
  }

  private async runWithErrorHandling<T>(operation: string, callback: () => Promise<T>): Promise<T> {
    try {
      return await callback();
    } catch (error) {
      if (error instanceof HttpException) {
        throw error;
      }

      if (error instanceof QueryFailedError) {
        const errorMessage = error.message.toLowerCase();
        if (errorMessage.includes('products_slug_key')) {
          throw new BadRequestException('A product with this slug already exists');
        }
        if (errorMessage.includes('product_variants_sku_key')) {
          throw new BadRequestException('A variant with this SKU already exists');
        }
        if (errorMessage.includes('product_variants_barcode_key')) {
          throw new BadRequestException('A variant with this barcode already exists');
        }
      }

      this.logger.error(`Unexpected error while trying to ${operation}`, error);
      throw new InternalServerErrorException(`Unable to ${operation} right now`);
    }
  }
}

